import{_ as a,a as o,b as t}from"./chunks/rag.Co53ISrY.js";import{_ as r,c as i,o as s,ag as n}from"./chunks/framework.Cycwnjj0.js";const l="/assets/tab-strip-component.BeZNBo5s.mp4",w=JSON.parse(`{"title":"What's New","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://sqlrooms.org/whats-new.html"}]]},"headers":[],"relativePath":"whats-new.md","filePath":"whats-new.md"}`),c={name:"whats-new.md"};function d(p,e,m,h,u,g){return s(),i("div",null,[...e[0]||(e[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /whats-new.md for this page in Markdown format</div><h1 id="what-s-new" tabindex="-1">What&#39;s New <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What&#39;s New&quot;">​</a></h1><p>New features, improvements, and notable changes in each SQLRooms release. For migration steps and breaking changes, see the <a href="/upgrade-guide.html">Upgrade Guide</a>.</p><h2 id="_0-27-0-rc-0" tabindex="-1">0.27.0-rc.0 <a class="header-anchor" href="#_0-27-0-rc-0" aria-label="Permalink to &quot;0.27.0-rc.0&quot;">​</a></h2><h3 id="introducing-mosaicslice" tabindex="-1">Introducing MosaicSlice <a class="header-anchor" href="#introducing-mosaicslice" aria-label="Permalink to &quot;Introducing MosaicSlice&quot;">​</a></h3><p>A new centralized state management system for Mosaic integration. The <code>MosaicSlice</code> provides a unified way to manage Mosaic connections, coordinate cross-filtering between visualizations, and create reactive data queries that automatically update based on user selections.</p><p><video src="'+a+'" alt="SQLRooms Deck.gl+Mosaic example app" width="450" controls loop muted></video></p><p>Key features:</p><ul><li>Automatic connection management with DuckDB</li><li>Named selections for cross-filtering between multiple visualizations</li><li><code>useMosaicClient</code> hook for custom visualization clients</li><li>Support for custom visualizations that respond to Mosaic selections</li></ul><p>See the <a href="/api/mosaic/">Mosaic API documentation</a> for details and check out the <a href="./examples.html#deck-gl-mosaic">DeckGL + Mosaic example</a> for a complete implementation.</p><h2 id="_0-26-1-rc-7-2025-12-05" tabindex="-1">0.26.1-rc.7 (2025-12-05) <a class="header-anchor" href="#_0-26-1-rc-7-2025-12-05" aria-label="Permalink to &quot;0.26.1-rc.7 (2025-12-05)&quot;">​</a></h2><h3 id="replaced-barrel-exports-across-all-modules" tabindex="-1">Replaced barrel exports across all modules <a class="header-anchor" href="#replaced-barrel-exports-across-all-modules" aria-label="Permalink to &quot;Replaced barrel exports across all modules&quot;">​</a></h3><p>Barrel exports (i.e., <code>export * from ...</code>) were replaced across all modules to improve tree-shaking, reduce bundle size, and avoid import path ambiguities. Direct/explicit exports now ensure only the required symbols are included in consumers&#39; builds, making dependencies clearer and preventing accidental re-exports or circular dependencies.</p><p>Additionally, <code>&quot;sideEffects&quot;: false</code> was added to all packages. This signals to bundlers that the modules are free of side effects, enabling better tree-shaking and further reducing the final bundle size.</p><h3 id="tabstrip-component-in-sqlrooms-ui" tabindex="-1">TabStrip component in <code>@sqlrooms/ui</code> <a class="header-anchor" href="#tabstrip-component-in-sqlrooms-ui" aria-label="Permalink to &quot;TabStrip component in `@sqlrooms/ui`&quot;">​</a></h3><p>A composable tab strip with drag-to-reorder, inline renaming, and a search dropdown for reopening closed tabs. Supports custom tab menus and flexible layouts via subcomponents (<code>TabStrip.Tabs</code>, <code>TabStrip.SearchDropdown</code>, <code>TabStrip.NewButton</code>).</p><p><video src="'+l+'" alt="SQLRooms TabStrip component" width="450" loop muted controls autoplay></video></p><h3 id="kepler-integration" tabindex="-1">Kepler integration <a class="header-anchor" href="#kepler-integration" aria-label="Permalink to &quot;Kepler integration&quot;">​</a></h3><p>Added <a href="https://kepler.gl/" target="_blank" rel="noreferrer">Kepler.gl</a> integration module for geospatial data visualization.</p><img src="'+o+'" alt="SQLRooms Kepler.gl geospatial visualization example" width="450"><p>Check the <a href="https://github.com/sqlrooms/examples/tree/main/kepler" target="_blank" rel="noreferrer">Kepler example</a></p><h3 id="ai-rag-module" tabindex="-1">AI RAG module <a class="header-anchor" href="#ai-rag-module" aria-label="Permalink to &quot;AI RAG module&quot;">​</a></h3><p>New <code>@sqlrooms/ai-rag</code> module for Retrieval Augmented Generation. Query your documentation using vector similarity search powered by DuckDB&#39;s native vector capabilities.</p><img src="'+t+'" alt="SQLRooms AI RAG example" width="450"><p>Check the <a href="https://github.com/sqlrooms/examples/tree/main/examples/ai-rag" target="_blank" rel="noreferrer">AI RAG example</a></p><h2 id="_0-26-0-2025-11-17" tabindex="-1">0.26.0 (2025-11-17) <a class="header-anchor" href="#_0-26-0-2025-11-17" aria-label="Permalink to &quot;0.26.0 (2025-11-17)&quot;">​</a></h2><h3 id="ai-sdk-v5" tabindex="-1">AI SDK v5 <a class="header-anchor" href="#ai-sdk-v5" aria-label="Permalink to &quot;AI SDK v5&quot;">​</a></h3><p>We migrated to Vercel AI SDK v5. Now supporting agents: check the <a href="https://github.com/sqlrooms/sqlrooms/tree/main/examples/ai-agent" target="_blank" rel="noreferrer">ai-agent example</a></p>',28)])])}const _=r(c,[["render",d]]);export{w as __pageData,_ as default};
